/* ------------------------------- Helpers -------------------------------- */
const uid = () => crypto?.randomUUID?.() || String(Math.random()).slice(2);
const num = (v) => (v === "" || v == null || isNaN(+v) ? null : +v);
const money = (n) => (n == null ? "—" : "$" + Math.round(n).toLocaleString());
const rate = (n) => (n == null ? "—" : "$" + (+n).toLocaleString(undefined, { maximumFractionDigits: 2 }));
const fmtDate = (iso) => { if (!iso) return "—"; const d = new Date(iso + "T00:00:00"); return isNaN(d) ? "—" : d.toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric" }); };

const daysOut = (iso) => {
  if (!iso) return null;
  const start = new Date(iso + "T00:00:00");
  if (isNaN(start)) return null;
  return Math.max(0, Math.floor((Date.now() - start.getTime()) / 86400000));
};

// All derived rental economics for one item, faithful to the spreadsheet logic.
function derive(it) {
  const monthlyEff = it.monthly != null ? it.monthly : it.daily != null ? it.daily * 30 : null;
  const days = daysOut(it.startDate);
  const rtd = monthlyEff != null && days != null ? (monthlyEff * days) / 30 : null;
  const be = it.purchase != null && monthlyEff ? it.purchase / monthlyEff : null;
  let rec = "none";
  if (it.purchase != null && monthlyEff) {
    if (rtd != null && rtd >= it.purchase) rec = "buy";
    else if (be != null && be <= 3) rec = "consider";
    else rec = "rent";
  } else if (monthlyEff != null) {
    rec = "rent";
  }
  return { monthlyEff, days, rtd, be, rec, annualized: monthlyEff != null ? monthlyEff * 12 : null };
}

function rollup(facility) {
  const t = { items: facility.items.length, daily: 0, monthly: 0, rtd: 0, purchase: 0, annualized: 0, review: 0 };
  facility.items.forEach((it) => {
    const d = derive(it);
    t.daily += it.daily || 0;
    t.monthly += d.monthlyEff || 0;
    t.rtd += d.rtd || 0;
    t.purchase += it.purchase || 0;
    t.annualized += d.annualized || 0;
    if (d.rec === "buy" || d.rec === "consider") t.review += 1;
  });
  return t;
}

