/* ------------------------------- Tracker -------------------------------- */
function Tracker({ auth, onLogout }) {
  const role = auth.user.role;
  const canSeeAll = role === "admin" || role === "corporate"; // sees every facility + portfolio
  const isAdmin = role === "admin";                            // also manages logins
  const [data, setData] = useState(null);
  const [loaded, setLoaded] = useState(false);
  const [saveError, setSaveError] = useState(false);
  const [view, setView] = useState(canSeeAll ? "corporate" : auth.user.facilityId);
  const [catFilter, setCatFilter] = useState("All");
  const [query, setQuery] = useState("");
  const [modal, setModal] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const b = await api(auth, "/api/bootstrap");
        setData({ facilities: b.facilities });
        if (!canSeeAll && b.facilities[0]) setView(b.facilities[0].id);
      } catch { setSaveError(true); }
      finally { setLoaded(true); }
    })();
  }, []);

  const facilities = data?.facilities || [];
  const facility = facilities.find((f) => f.id === view) || null;

  const edit = (fn) => setData((d) => { const n = structuredClone(d); fn(n); return n; });
  const getF = (d, id) => d.facilities.find((f) => f.id === id);

  const saveItem = async (fid, item) => {
    try {
      const exists = item.id && getF(data, fid)?.items.some((x) => x.id === item.id);
      const saved = exists
        ? await api(auth, `/api/items/${item.id}`, "PATCH", item)
        : await api(auth, `/api/facilities/${fid}/items`, "POST", item);
      edit((d) => {
        const f = getF(d, fid); if (!f) return;
        f.items = exists ? f.items.map((x) => (x.id === saved.id ? saved : x)) : [...f.items, saved];
      });
    } catch { setSaveError(true); }
  };
  const deleteItem = async (fid, iid) => {
    try { await api(auth, `/api/items/${iid}`, "DELETE"); edit((d) => { const f = getF(d, fid); if (f) f.items = f.items.filter((x) => x.id !== iid); }); }
    catch { setSaveError(true); }
  };
  const editFacility = async (fid, patch) => {
    try { const saved = await api(auth, `/api/facilities/${fid}`, "PATCH", patch); edit((d) => { const f = getF(d, fid); if (f) Object.assign(f, saved); }); }
    catch { setSaveError(true); }
  };

  if (!loaded) return (
    <div className="min-h-screen flex items-center justify-center" style={{ background: BRAND.paper, color: BRAND.inkSoft }}>
      <div className="flex flex-col items-center gap-3"><Crown size={34} /><span className="text-sm">Loading rental tracker…</span></div>
    </div>
  );

  const portfolio = facilities.reduce((a, f) => {
    const r = rollup(f);
    a.items += r.items; a.monthly += r.monthly; a.rtd += r.rtd; a.purchase += r.purchase; a.annualized += r.annualized; a.review += r.review; a.daily += r.daily;
    return a;
  }, { items: 0, daily: 0, monthly: 0, rtd: 0, purchase: 0, annualized: 0, review: 0 });

  return (
    <div className="min-h-screen" style={{ background: BRAND.paper, color: BRAND.ink, fontFamily: "ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, sans-serif" }}>
      {/* Masthead */}
      <header style={{ background: BRAND.ink }} className="text-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 py-4 flex items-center justify-between gap-4">
          <div className="flex items-center gap-3 min-w-0">
            <Crown size={30} color={BRAND.tan} />
            <div className="min-w-0 leading-tight">
              <div className="text-lg sm:text-xl tracking-wide" style={{ fontFamily: SERIF }}>Eminent Care Group</div>
              <div className="text-[10px] sm:text-[11px] uppercase tracking-[0.22em]" style={{ color: BRAND.tan }}>Equipment Rental Tracker</div>
            </div>
          </div>
          <div className="flex items-center gap-4 shrink-0">
            <div className="text-right hidden sm:block leading-tight">
              <div className="text-[11px] uppercase tracking-[0.18em] text-white/45">{role === "admin" ? "Administrator" : role === "corporate" ? "Corporate" : "Facility"}</div>
              <div className="text-xs text-white/80">{auth.user.email}</div>
            </div>
            <button onClick={onLogout} className="text-xs rounded-lg px-3 py-2 transition-colors" style={{ border: `1px solid rgba(255,255,255,0.2)`, color: "rgba(255,255,255,0.8)" }}>
              Sign out
            </button>
          </div>
        </div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6">
          <nav className="flex items-center gap-0.5 overflow-x-auto -mb-px">
            {canSeeAll && (
              <Tab active={view === "corporate"} onClick={() => setView("corporate")} icon={LayoutDashboard}>Portfolio</Tab>
            )}
            {facilities.map((f) => {
              const r = rollup(f);
              return (
                <Tab key={f.id} active={view === f.id} onClick={() => { setView(f.id); setCatFilter("All"); setQuery(""); }} badge={r.review || null}>
                  {f.name}
                </Tab>
              );
            })}
            {isAdmin && (
              <Tab active={view === "users"} onClick={() => setView("users")} icon={Users}>Logins</Tab>
            )}
            {isAdmin && (
              <Tab active={view === "audit"} onClick={() => setView("audit")} icon={History}>Activity</Tab>
            )}
          </nav>
        </div>
      </header>

      {saveError && (
        <div className="text-sm px-4 py-2 text-center" style={{ background: "#fbf1da", color: "#8f6716" }}>
          Couldn’t reach the server. Some changes may not have saved — refresh to reload the latest data.
        </div>
      )}

      <main className="max-w-7xl mx-auto px-4 sm:px-6 py-7">
        {view === "users" && isAdmin ? (
          <UserManager auth={auth} facilities={facilities} meId={auth.user.id} />
        ) : view === "audit" && isAdmin ? (
          <AuditLog auth={auth} />
        ) : view === "corporate" ? (
          <Portfolio facilities={facilities} totals={portfolio} onOpen={(id) => { setView(id); setCatFilter("All"); }} />
        ) : facility ? (
          <Facility
            facility={facility}
            catFilter={catFilter} setCatFilter={setCatFilter}
            query={query} setQuery={setQuery}
            onAdd={() => setModal({ type: "item", fid: facility.id })}
            onEditItem={(it) => setModal({ type: "item", fid: facility.id, item: it })}
            onDeleteItem={(it) => setModal({ type: "confirm", title: "Remove item?", body: `${it.equipment || "This item"} for ${it.resident || "—"} will be deleted.`, onYes: () => deleteItem(facility.id, it.id) })}
            onEditFacility={() => setModal({ type: "facility", facility })}
          />
        ) : null}
      </main>

      {modal?.type === "item" && (
        <ItemModal item={modal.item} onClose={() => setModal(null)} onSave={(it) => { saveItem(modal.fid, it); setModal(null); }} />
      )}
      {modal?.type === "facility" && (
        <FacilityModal facility={modal.facility} onClose={() => setModal(null)}
          onSave={(patch) => { editFacility(modal.facility.id, patch); setModal(null); }} />
      )}
      {modal?.type === "confirm" && (
        <Confirm title={modal.title} body={modal.body} onClose={() => setModal(null)} onYes={() => { modal.onYes(); setModal(null); }} />
      )}
    </div>
  );
}

/* --------------------------- Login manager ----------------------------- */
const ROLE_LABEL = { admin: "Administrator", corporate: "Corporate", facility: "Facility" };
const genPw = () =>
  Math.random().toString(36).slice(2, 6) + "-" + Math.random().toString(36).slice(2, 6);

function UserManager({ auth, facilities, meId }) {
  const [users, setUsers] = useState(null);
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);
  const [created, setCreated] = useState(null);   // { email, password } just-made, to hand off
  const [resetId, setResetId] = useState(null);
  const [resetPw, setResetPw] = useState("");
  const [form, setForm] = useState({ email: "", role: "facility", facilityId: facilities[0]?.id || "", password: genPw() });

  useEffect(() => {
    (async () => {
      try { setUsers(await api(auth, "/api/users")); }
      catch (e) { setErr(e.message || "Couldn't load logins."); }
    })();
  }, []);

  const set = (k, v) => setForm((p) => ({ ...p, [k]: v }));

  const addUser = async () => {
    setErr(""); setBusy(true);
    try {
      const body = {
        email: form.email.trim(),
        role: form.role,
        facilityId: form.role === "facility" ? form.facilityId : null,
        password: form.password,
      };
      const u = await api(auth, "/api/users", "POST", body);
      setUsers((list) => [u, ...(list || [])]);
      setCreated({ email: u.email, password: form.password });
      setForm({ email: "", role: "facility", facilityId: facilities[0]?.id || "", password: genPw() });
    } catch (e) { setErr(e.message || "Couldn't create the login."); }
    finally { setBusy(false); }
  };

  const doReset = async (id) => {
    setErr(""); setBusy(true);
    try {
      await api(auth, `/api/users/${id}/password`, "PATCH", { password: resetPw });
      const u = users.find((x) => x.id === id);
      setCreated({ email: u.email, password: resetPw });
      setResetId(null); setResetPw("");
    } catch (e) { setErr(e.message || "Couldn't reset the password."); }
    finally { setBusy(false); }
  };

  const removeUser = async (id) => {
    setErr(""); setBusy(true);
    try {
      await api(auth, `/api/users/${id}`, "DELETE");
      setUsers((list) => list.filter((x) => x.id !== id));
    } catch (e) { setErr(e.message || "Couldn't remove the login."); }
    finally { setBusy(false); }
  };

  return (
    <div>
      <Eyebrow>Access</Eyebrow>
      <div className="flex items-end justify-between gap-4 mb-2">
        <h2 className="text-2xl sm:text-3xl" style={{ fontFamily: SERIF }}>Logins</h2>
      </div>
      <p className="text-sm mb-6" style={{ color: BRAND.inkSoft }}>
        Administrators see and edit every facility and manage logins. Corporate sees every facility but not this page.
        A facility login only ever sees its own building.
      </p>

      {/* Add a login */}
      <div className="rounded-2xl p-5 mb-6" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        <div className="text-sm mb-3" style={{ fontFamily: SERIF }}>Add a login</div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-3">
          <Field label="Email"><input style={inp} type="email" value={form.email} onChange={(e) => set("email", e.target.value)} placeholder="name@eminentcare.com" /></Field>
          <Field label="Access level">
            <select style={inp} value={form.role} onChange={(e) => set("role", e.target.value)}>
              <option value="facility">Facility — one building only</option>
              <option value="corporate">Corporate — all buildings, no login manager</option>
              <option value="admin">Administrator — all buildings + manages logins</option>
            </select>
          </Field>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-3">
          {form.role === "facility" ? (
            <Field label="Facility">
              <select style={inp} value={form.facilityId} onChange={(e) => set("facilityId", e.target.value)}>
                {facilities.map((f) => <option key={f.id} value={f.id}>{f.name}</option>)}
              </select>
            </Field>
          ) : <div />}
          <Field label="Temporary password">
            <div className="flex gap-2">
              <input style={inp} value={form.password} onChange={(e) => set("password", e.target.value)} />
              <button onClick={() => set("password", genPw())} className="shrink-0 px-3 rounded-lg text-xs" style={{ border: `1px solid ${BRAND.line}`, color: BRAND.inkSoft }}>New</button>
            </div>
          </Field>
        </div>
        {err && <div className="text-xs mb-3" style={{ color: "#9a3826" }}>{err}</div>}
        <div className="flex justify-end">
          <button disabled={busy} onClick={addUser} className="inline-flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm text-white" style={{ background: BRAND.ink, opacity: busy ? 0.6 : 1 }}>
            <Plus size={15} /> Create login
          </button>
        </div>
        {created && (
          <div className="mt-4 rounded-lg px-4 py-3 text-sm" style={{ background: "#e8f1ea", color: "#3c6850" }}>
            Share this once, then have them change it: <span className="font-semibold">{created.email}</span> · password <span className="font-mono">{created.password}</span>
            <button onClick={() => setCreated(null)} className="ml-2 underline">dismiss</button>
          </div>
        )}
      </div>

      {/* Existing logins */}
      <div className="rounded-2xl overflow-hidden" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        {users === null ? (
          <div className="px-5 py-6 text-sm" style={{ color: BRAND.inkSoft }}>Loading logins…</div>
        ) : users.length === 0 ? (
          <div className="px-5 py-6 text-sm" style={{ color: BRAND.inkSoft }}>No logins yet.</div>
        ) : users.map((u) => (
          <div key={u.id} className="px-5 py-3 flex items-center justify-between gap-3" style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
            <div className="min-w-0">
              <div className="text-sm truncate">{u.email}{u.id === meId && <span className="text-[11px] ml-2" style={{ color: BRAND.inkSoft }}>(you)</span>}</div>
              <div className="text-[11px] uppercase tracking-wider mt-0.5" style={{ color: BRAND.inkSoft }}>
                {ROLE_LABEL[u.role]}{u.role === "facility" && u.facilityName ? ` · ${u.facilityName}` : ""}
              </div>
            </div>
            {resetId === u.id ? (
              <div className="flex items-center gap-2 shrink-0">
                <input style={{ ...inp, width: 150 }} value={resetPw} onChange={(e) => setResetPw(e.target.value)} placeholder="new password" />
                <button onClick={() => setResetPw(genPw())} className="px-2 rounded-lg text-xs" style={{ border: `1px solid ${BRAND.line}`, color: BRAND.inkSoft }}>New</button>
                <button disabled={busy || resetPw.length < 8} onClick={() => doReset(u.id)} className="px-3 py-1.5 rounded-lg text-xs text-white" style={{ background: BRAND.ink, opacity: resetPw.length < 8 ? 0.5 : 1 }}>Save</button>
                <button onClick={() => { setResetId(null); setResetPw(""); }} className="text-xs" style={{ color: BRAND.inkSoft }}>Cancel</button>
              </div>
            ) : (
              <div className="flex items-center gap-1 shrink-0">
                <button onClick={() => { setResetId(u.id); setResetPw(genPw()); setErr(""); }} className="inline-flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs" style={{ color: BRAND.inkSoft }}>
                  <KeyRound size={14} /> Reset password
                </button>
                {u.id !== meId && (
                  <button onClick={() => removeUser(u.id)} className="inline-flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs" style={{ color: "#9a3826" }}>
                    <Trash2 size={14} /> Remove
                  </button>
                )}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

/* ---------------------------- Activity log ----------------------------- */
const ACTION_LABEL = {
  "login": "Signed in",
  "login_failed": "Failed sign-in",
  "item.create": "Added item",
  "item.update": "Edited item",
  "item.delete": "Deleted item",
  "facility.update": "Edited facility",
  "user.create": "Created login",
  "user.reset_password": "Reset password",
  "user.delete": "Removed login",
  "password.forgot_sent": "Reset link emailed",
  "password.forgot_unknown": "Reset requested (no account)",
  "password.reset": "Password reset (self-service)",
};
const ACTION_TONE = (a) =>
  a === "login_failed" || a.endsWith(".delete") || a === "user.delete" ? "#9a3826"
  : a.startsWith("user.") ? "#8f6716"
  : "#3c6850";

function AuditLog({ auth }) {
  const [rows, setRows] = useState(null);
  const [err, setErr] = useState("");

  const load = async () => {
    setErr("");
    try { setRows(await api(auth, "/api/audit")); }
    catch (e) { setErr(e.message || "Couldn't load the activity log."); }
  };
  useEffect(() => { load(); }, []);

  return (
    <div>
      <Eyebrow>Access</Eyebrow>
      <div className="flex items-end justify-between gap-4 mb-2">
        <h2 className="text-2xl sm:text-3xl" style={{ fontFamily: SERIF }}>Activity</h2>
        <button onClick={load} className="text-xs rounded-lg px-3 py-2" style={{ border: `1px solid ${BRAND.line}`, color: BRAND.inkSoft }}>Refresh</button>
      </div>
      <p className="text-sm mb-6" style={{ color: BRAND.inkSoft }}>
        A running record of sign-ins and every change. Entries are only ever added, never edited — showing the most recent 200.
      </p>

      {err && <div className="text-xs mb-3" style={{ color: "#9a3826" }}>{err}</div>}

      <div className="rounded-2xl overflow-hidden" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        {rows === null ? (
          <div className="px-5 py-6 text-sm" style={{ color: BRAND.inkSoft }}>Loading activity…</div>
        ) : rows.length === 0 ? (
          <div className="px-5 py-6 text-sm" style={{ color: BRAND.inkSoft }}>No activity recorded yet.</div>
        ) : rows.map((r) => (
          <div key={r.id} className="px-5 py-3 flex items-start justify-between gap-4" style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
            <div className="min-w-0">
              <div className="text-sm">
                <span style={{ color: ACTION_TONE(r.action), fontWeight: 500 }}>{ACTION_LABEL[r.action] || r.action}</span>
                {r.facilityName && <span style={{ color: BRAND.inkSoft }}> · {r.facilityName}</span>}
              </div>
              <div className="text-[12px] mt-0.5 truncate" style={{ color: BRAND.inkSoft }}>
                {r.email || "—"}{r.detail ? ` · ${r.detail}` : ""}
              </div>
            </div>
            <div className="text-[11px] whitespace-nowrap shrink-0 tabular-nums" style={{ color: BRAND.inkSoft }}>
              {new Date(r.at).toLocaleString()}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

/* -------------------------------- Tabs ---------------------------------- */
function Tab({ active, onClick, icon: Icon, badge, children }) {
  return (
    <button onClick={onClick}
      className="shrink-0 inline-flex items-center gap-2 px-3 sm:px-4 py-3 text-sm border-b-2 whitespace-nowrap transition-colors"
      style={{ borderColor: active ? BRAND.tan : "transparent", color: active ? "#fff" : "rgba(255,255,255,0.5)" }}>
      {Icon && <Icon size={15} />}
      <span style={{ fontFamily: SERIF, letterSpacing: "0.01em" }}>{children}</span>
      {badge ? <span className="text-[10px] font-semibold rounded-full px-1.5 py-0.5 tabular-nums" style={{ background: BRAND.tan, color: BRAND.ink }}>{badge}</span> : null}
    </button>
  );
}

/* ----------------------------- Portfolio -------------------------------- */
function Portfolio({ facilities, totals, onOpen }) {
  const catTotals = useMemo(() => {
    const m = {}; CATEGORIES.forEach((c) => (m[c] = 0));
    facilities.forEach((f) => f.items.forEach((it) => { const d = derive(it); if (d.monthlyEff) m[it.category] = (m[it.category] || 0) + d.monthlyEff; }));
    return m;
  }, [facilities]);
  const maxCat = Math.max(1, ...Object.values(catTotals));

  return (
    <div>
      <Eyebrow>Portfolio summary</Eyebrow>
      <div className="flex items-end justify-between gap-4 mb-6">
        <h2 className="text-2xl sm:text-3xl" style={{ fontFamily: SERIF }}>Rental exposure across {facilities.length} facilities</h2>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 mb-8">
        <Stat label="Active rentals" value={totals.items} />
        <Stat label="Monthly spend" value={money(totals.monthly)} accent />
        <Stat label="Rental to date" value={money(totals.rtd)} />
        <Stat label="Flagged to review" value={totals.review} review={totals.review > 0} />
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* facility table */}
        <div className="lg:col-span-2 rounded-xl overflow-hidden" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr style={{ background: BRAND.lineSoft, color: BRAND.inkSoft }} className="text-left text-[11px] uppercase tracking-wider">
                  <th className="px-4 py-2.5 font-medium">Facility</th>
                  <th className="px-3 py-2.5 font-medium text-right">Items</th>
                  <th className="px-3 py-2.5 font-medium text-right">Monthly</th>
                  <th className="px-3 py-2.5 font-medium text-right">To date</th>
                  <th className="px-3 py-2.5 font-medium text-right">Annualized</th>
                  <th className="px-3 py-2.5 font-medium text-right">Review</th>
                  <th className="px-2 py-2.5"></th>
                </tr>
              </thead>
              <tbody>
                {facilities.map((f) => {
                  const r = rollup(f);
                  return (
                    <tr key={f.id} onClick={() => onOpen(f.id)} className="cursor-pointer transition-colors hover:bg-black/[0.02]"
                      style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2.5">
                          <Crown size={18} />
                          <span style={{ fontFamily: SERIF }} className="text-[15px]">{f.name}</span>
                        </div>
                      </td>
                      <td className="px-3 py-3 text-right tabular-nums" style={{ color: r.items ? BRAND.ink : "#b8b2a6" }}>{r.items}</td>
                      <td className="px-3 py-3 text-right tabular-nums">{r.monthly ? money(r.monthly) : "—"}</td>
                      <td className="px-3 py-3 text-right tabular-nums">{r.rtd ? money(r.rtd) : "—"}</td>
                      <td className="px-3 py-3 text-right tabular-nums" style={{ color: BRAND.inkSoft }}>{r.annualized ? money(r.annualized) : "—"}</td>
                      <td className="px-3 py-3 text-right">
                        {r.review ? <span className="inline-block text-xs font-semibold rounded-full px-2 py-0.5 tabular-nums" style={{ background: REC.buy.bg, color: REC.buy.fg }}>{r.review}</span> : <span style={{ color: "#c4beb2" }}>—</span>}
                      </td>
                      <td className="px-2 py-3 text-right"><ChevronRight size={16} style={{ color: "#c4beb2" }} /></td>
                    </tr>
                  );
                })}
                <tr style={{ borderTop: `2px solid ${BRAND.line}`, background: BRAND.lineSoft }}>
                  <td className="px-4 py-3 font-semibold" style={{ fontFamily: SERIF }}>Portfolio total</td>
                  <td className="px-3 py-3 text-right tabular-nums font-semibold">{totals.items}</td>
                  <td className="px-3 py-3 text-right tabular-nums font-semibold">{money(totals.monthly)}</td>
                  <td className="px-3 py-3 text-right tabular-nums font-semibold">{money(totals.rtd)}</td>
                  <td className="px-3 py-3 text-right tabular-nums font-semibold">{money(totals.annualized)}</td>
                  <td className="px-3 py-3 text-right tabular-nums font-semibold">{totals.review}</td>
                  <td></td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>

        {/* category spend + legend */}
        <div className="space-y-6">
          <div className="rounded-xl p-5" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
            <div className="text-[11px] uppercase tracking-wider mb-3" style={{ color: BRAND.inkSoft }}>Monthly spend by category</div>
            <div className="space-y-2.5">
              {CATEGORIES.map((c) => (
                <div key={c}>
                  <div className="flex justify-between text-xs mb-1"><span>{c}</span><span className="tabular-nums" style={{ color: BRAND.inkSoft }}>{money(catTotals[c])}</span></div>
                  <div className="h-1.5 rounded-full" style={{ background: BRAND.lineSoft }}>
                    <div className="h-1.5 rounded-full" style={{ width: `${(catTotals[c] / maxCat) * 100}%`, background: BRAND.tan }} />
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="rounded-xl p-5" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
            <div className="text-[11px] uppercase tracking-wider mb-3" style={{ color: BRAND.inkSoft }}>Recommendation key</div>
            <div className="space-y-2.5 text-xs">
              <LegendRow tone={REC.buy} text="Rental spend has met or passed the purchase price — buy it." />
              <LegendRow tone={REC.consider} text="Item pays for itself within ~3 months — likely buy." />
              <LegendRow tone={REC.rent} text="Renting is still cheaper than buying for now." />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function LegendRow({ tone, text }) {
  return (
    <div className="flex gap-2.5 items-start">
      <span className="mt-1 h-2 w-2 rounded-full shrink-0" style={{ background: tone.dot }} />
      <span style={{ color: BRAND.inkSoft }}>{text}</span>
    </div>
  );
}

function Stat({ label, value, accent, review }) {
  return (
    <div className="rounded-xl p-4" style={{ background: BRAND.card, border: `1px solid ${review ? REC.buy.dot : BRAND.line}` }}>
      <div className="text-2xl sm:text-3xl tabular-nums" style={{ fontFamily: SERIF, color: accent ? BRAND.tanDeep : review ? REC.buy.fg : BRAND.ink }}>{value}</div>
      <div className="text-[11px] uppercase tracking-wider mt-1.5" style={{ color: BRAND.inkSoft }}>{label}</div>
    </div>
  );
}

function Eyebrow({ children }) {
  return <div className="text-[11px] uppercase tracking-[0.22em] mb-2 flex items-center gap-2" style={{ color: BRAND.tanDeep }}><Crown size={16} /> {children}</div>;
}

/* ------------------------------ Facility -------------------------------- */
function Facility({ facility, catFilter, setCatFilter, query, setQuery, onAdd, onEditItem, onDeleteItem, onEditFacility }) {
  const r = rollup(facility);
  const tabs = ["All", ...CATEGORIES.filter((c) => facility.items.some((it) => it.category === c))];
  if (!tabs.includes(catFilter)) catFilter = "All";

  const items = useMemo(() => {
    const q = query.trim().toLowerCase();
    return facility.items
      .filter((it) => catFilter === "All" || it.category === catFilter)
      .filter((it) => !q || [it.resident, it.room, it.equipment, it.comments, it.vendor].some((v) => (v || "").toLowerCase().includes(q)))
      .map((it) => ({ ...it, d: derive(it) }))
      .sort((a, b) => ({ buy: 0, consider: 1, rent: 2, none: 3 })[a.d.rec] - ({ buy: 0, consider: 1, rent: 2, none: 3 })[b.d.rec]);
  }, [facility, catFilter, query]);

  return (
    <div>
      {/* facility wordmark header */}
      <div className="flex flex-col items-center text-center mb-1">
        {LOGOS[facility.name] ? (
          <img src={LOGOS[facility.name]} alt={facility.name} className="h-20 sm:h-24 w-auto object-contain" />
        ) : (
          <>
            <Crown size={30} />
            <h2 className="text-3xl sm:text-4xl mt-2" style={{ fontFamily: SERIF }}>{facility.name}</h2>
            <div className="text-[11px] uppercase tracking-[0.28em] mt-1" style={{ color: BRAND.inkSoft }}>{facility.tagline}</div>
          </>
        )}
        {facility.location && (
          <button onClick={onEditFacility} className="text-xs mt-1.5 inline-flex items-center gap-1 hover:opacity-70" style={{ color: BRAND.inkSoft }}>
            <MapPin size={12} /> {facility.location} <Pencil size={11} />
          </button>
        )}
        {!facility.location && (
          <button onClick={onEditFacility} className="text-xs mt-1.5 inline-flex items-center gap-1 hover:opacity-70" style={{ color: BRAND.tanDeep }}>
            <Plus size={12} /> Add location
          </button>
        )}
      </div>

      {/* summary strip */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 my-6">
        <MiniStat label="Items" value={r.items} />
        <MiniStat label="Monthly" value={money(r.monthly)} />
        <MiniStat label="To date" value={money(r.rtd)} />
        <MiniStat label="To review" value={r.review} flag={r.review > 0} />
      </div>

      {/* category tabs + toolbar */}
      <div className="flex flex-wrap items-center justify-between gap-3 mb-3">
        <div className="flex items-center gap-1 overflow-x-auto">
          {tabs.map((c) => (
            <button key={c} onClick={() => setCatFilter(c)}
              className="shrink-0 px-3 py-1.5 rounded-full text-sm whitespace-nowrap transition-colors"
              style={catFilter === c ? { background: BRAND.ink, color: "#fff" } : { color: BRAND.inkSoft, background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
              {c}
            </button>
          ))}
        </div>
        <div className="flex items-center gap-2 flex-1 sm:flex-none justify-end">
          <div className="relative flex-1 sm:w-56">
            <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2" style={{ color: "#b3ada1" }} />
            <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search resident, equipment…"
              className="w-full pl-9 pr-3 py-2 rounded-lg text-sm outline-none"
              style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }} />
          </div>
          <button onClick={onAdd} className="inline-flex items-center gap-1.5 rounded-lg px-3.5 py-2 text-sm text-white shrink-0" style={{ background: BRAND.ink }}>
            <Plus size={16} /> <span className="hidden sm:inline">Add item</span>
          </button>
        </div>
      </div>

      {facility.items.length === 0 ? (
        <Empty onAdd={onAdd} />
      ) : items.length === 0 ? (
        <div className="text-center py-12 text-sm" style={{ color: BRAND.inkSoft }}>No items match your filters.</div>
      ) : (
        <div className="rounded-xl overflow-hidden" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr style={{ background: BRAND.lineSoft, color: BRAND.inkSoft }} className="text-left text-[11px] uppercase tracking-wider whitespace-nowrap">
                  {["Resident", "Room", "Status", "Equipment", "Category", "Start", "Days", "Daily", "Monthly", "To date", "Purchase", "Break-even", "Recommendation", ""].map((h, i) => (
                    <th key={i} className={`px-3 py-2.5 font-medium ${["Days", "Daily", "Monthly", "To date", "Purchase", "Break-even"].includes(h) ? "text-right" : ""}`}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {items.map((it) => {
                  const rec = REC[it.d.rec];
                  const st = STATUS[it.status] || STATUS["Active"];
                  return (
                    <tr key={it.id} className="group transition-colors hover:bg-black/[0.015]" style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
                      <td className="px-3 py-3 font-medium whitespace-nowrap">{it.resident || "—"}</td>
                      <td className="px-3 py-3 whitespace-nowrap" style={{ color: BRAND.inkSoft }}>{it.room || "—"}</td>
                      <td className="px-3 py-3 whitespace-nowrap">
                        <span className="inline-flex items-center gap-1.5 text-xs" style={{ color: st.fg }}>
                          <span className="h-1.5 w-1.5 rounded-full" style={{ background: st.dot }} />{it.status}
                        </span>
                      </td>
                      <td className="px-3 py-3 min-w-[180px]">{it.equipment || "—"}{it.comments && <div className="text-xs mt-0.5" style={{ color: BRAND.inkSoft }}>{it.comments}</div>}</td>
                      <td className="px-3 py-3 whitespace-nowrap" style={{ color: BRAND.inkSoft }}>{it.category}</td>
                      <td className="px-3 py-3 whitespace-nowrap" style={{ color: BRAND.inkSoft }}>{fmtDate(it.startDate)}</td>
                      <td className="px-3 py-3 text-right tabular-nums" style={{ color: BRAND.inkSoft }}>{it.d.days ?? "—"}</td>
                      <td className="px-3 py-3 text-right tabular-nums">{rate(it.daily)}</td>
                      <td className="px-3 py-3 text-right tabular-nums">{it.d.monthlyEff != null ? money(it.d.monthlyEff) : "—"}</td>
                      <td className="px-3 py-3 text-right tabular-nums">{it.d.rtd != null ? money(it.d.rtd) : "—"}</td>
                      <td className="px-3 py-3 text-right tabular-nums">{money(it.purchase)}</td>
                      <td className="px-3 py-3 text-right tabular-nums" style={{ color: BRAND.inkSoft }}>{it.d.be != null ? it.d.be.toFixed(1) + " mo" : "—"}</td>
                      <td className="px-3 py-3">
                        <span className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium whitespace-nowrap" style={{ background: rec.bg, color: rec.fg }}>
                          <span className="h-1.5 w-1.5 rounded-full" style={{ background: rec.dot }} />{rec.label}
                        </span>
                      </td>
                      <td className="px-2 py-3">
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          <IconBtn title="Edit" onClick={() => onEditItem(it)}><Pencil size={14} /></IconBtn>
                          <IconBtn title="Delete" danger onClick={() => onDeleteItem(it)}><Trash2 size={14} /></IconBtn>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

function MiniStat({ label, value, flag }) {
  return (
    <div className="rounded-lg px-4 py-3" style={{ background: BRAND.card, border: `1px solid ${flag ? REC.buy.dot : BRAND.line}` }}>
      <div className="text-xl tabular-nums" style={{ fontFamily: SERIF, color: flag ? REC.buy.fg : BRAND.ink }}>{value}</div>
      <div className="text-[10px] uppercase tracking-wider mt-0.5" style={{ color: BRAND.inkSoft }}>{label}</div>
    </div>
  );
}

function Empty({ onAdd }) {
  return (
    <div className="text-center rounded-xl py-14 px-6" style={{ background: BRAND.card, border: `1px dashed ${BRAND.line}` }}>
      <div className="flex justify-center mb-3"><Crown size={28} /></div>
      <h3 style={{ fontFamily: SERIF }} className="text-lg">No rentals tracked yet</h3>
      <p className="text-sm mt-1 max-w-sm mx-auto" style={{ color: BRAND.inkSoft }}>Add the equipment this facility is renting and the tracker will calculate days out, spend to date, and whether to keep renting or buy.</p>
      <button onClick={onAdd} className="mt-4 inline-flex items-center gap-1.5 rounded-lg px-4 py-2 text-sm text-white" style={{ background: BRAND.ink }}><Plus size={16} /> Add item</button>
    </div>
  );
}

/* ------------------------------ Shared UI ------------------------------- */
function IconBtn({ children, onClick, title, danger }) {
  return (
    <button title={title} onClick={onClick} className="p-1.5 rounded-md transition-colors"
      style={{ color: danger ? "#b9472f" : BRAND.inkSoft }}
      onMouseEnter={(e) => (e.currentTarget.style.background = danger ? "#fbe9e4" : BRAND.lineSoft)}
      onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}>
      {children}
    </button>
  );
}

function Shell({ title, onClose, children, wide }) {
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ background: "rgba(27,34,56,0.45)" }} onClick={onClose}>
      <div className={`w-full ${wide ? "max-w-lg" : "max-w-md"} rounded-2xl overflow-hidden`} style={{ background: BRAND.card }} onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between px-5 py-4" style={{ borderBottom: `1px solid ${BRAND.line}` }}>
          <h3 className="text-lg flex items-center gap-2" style={{ fontFamily: SERIF }}><Crown size={18} /> {title}</h3>
          <button onClick={onClose} style={{ color: BRAND.inkSoft }}><X size={20} /></button>
        </div>
        <div className="p-5">{children}</div>
      </div>
    </div>
  );
}

const inp = { width: "100%", padding: "8px 12px", borderRadius: 8, border: `1px solid ${BRAND.line}`, fontSize: 14, outline: "none", background: "#fff" };
function Field({ label, children, half }) {
  return (
    <label className={`block mb-3 ${half ? "" : ""}`}>
      <span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>{label}</span>
      {children}
    </label>
  );
}

function ItemModal({ item, onClose, onSave }) {
  const [f, setF] = useState({
    id: item?.id, resident: item?.resident || "", room: item?.room || "",
    status: item?.status || "Active", equipment: item?.equipment || "", category: item?.category || "Mattress/Bed",
    vendor: item?.vendor || "", startDate: item?.startDate || "",
    daily: item?.daily ?? "", monthly: item?.monthly ?? "", purchase: item?.purchase ?? "", comments: item?.comments || "",
  });
  const set = (k, v) => setF((p) => ({ ...p, [k]: v }));
  const clean = { ...f, daily: num(f.daily), monthly: num(f.monthly), purchase: num(f.purchase), resident: f.resident.trim(), equipment: f.equipment.trim() };
  const d = derive(clean);
  const rec = REC[d.rec];
  const ok = clean.equipment.length > 0;

  return (
    <Shell title={item ? "Edit rental item" : "Add rental item"} onClose={onClose} wide>
      <div className="grid grid-cols-2 gap-x-3">
        <Field label="Resident"><input style={inp} value={f.resident} onChange={(e) => set("resident", e.target.value)} placeholder="Last, First" autoFocus /></Field>
        <Field label="Room #"><input style={inp} value={f.room} onChange={(e) => set("room", e.target.value)} /></Field>
      </div>
      <Field label="Equipment"><input style={inp} value={f.equipment} onChange={(e) => set("equipment", e.target.value)} placeholder='e.g. 36" air mattress' /></Field>
      <div className="grid grid-cols-2 gap-x-3">
        <Field label="Category">
          <select style={inp} value={f.category} onChange={(e) => set("category", e.target.value)}>{CATEGORIES.map((c) => <option key={c}>{c}</option>)}</select>
        </Field>
        <Field label="Status">
          <select style={inp} value={f.status} onChange={(e) => set("status", e.target.value)}>{STATUSES.map((s) => <option key={s}>{s}</option>)}</select>
        </Field>
      </div>
      <div className="grid grid-cols-2 gap-x-3">
        <Field label="Vendor"><input style={inp} value={f.vendor} onChange={(e) => set("vendor", e.target.value)} /></Field>
        <Field label="Start date"><input type="date" style={inp} value={f.startDate} onChange={(e) => set("startDate", e.target.value)} /></Field>
      </div>
      <div className="grid grid-cols-3 gap-x-3">
        <Field label="Daily ($)"><input style={inp} inputMode="decimal" value={f.daily} onChange={(e) => set("daily", e.target.value)} /></Field>
        <Field label="Monthly ($)"><input style={inp} inputMode="decimal" value={f.monthly} onChange={(e) => set("monthly", e.target.value)} placeholder={f.daily ? String(num(f.daily) * 30) : ""} /></Field>
        <Field label="Purchase ($)"><input style={inp} inputMode="decimal" value={f.purchase} onChange={(e) => set("purchase", e.target.value)} /></Field>
      </div>
      <Field label="Comments"><textarea rows={2} style={inp} value={f.comments} onChange={(e) => set("comments", e.target.value)} /></Field>

      {/* live recommendation */}
      <div className="rounded-lg px-4 py-3 mb-4 flex items-center justify-between gap-3" style={{ background: BRAND.lineSoft }}>
        <div className="text-xs space-y-0.5" style={{ color: BRAND.inkSoft }}>
          <div>{d.days != null ? `${d.days} days out` : "No start date"} · to date {d.rtd != null ? money(d.rtd) : "—"} · break-even {d.be != null ? d.be.toFixed(1) + " mo" : "—"}</div>
        </div>
        <span className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium whitespace-nowrap" style={{ background: rec.bg, color: rec.fg }}>
          <span className="h-1.5 w-1.5 rounded-full" style={{ background: rec.dot }} />{rec.label}
        </span>
      </div>

      <div className="flex justify-end gap-2">
        <button onClick={onClose} className="px-4 py-2 rounded-lg text-sm" style={{ color: BRAND.inkSoft }}>Cancel</button>
        <button disabled={!ok} onClick={() => onSave(clean)} className="inline-flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm text-white" style={{ background: ok ? BRAND.ink : "#bdb7ab", cursor: ok ? "pointer" : "not-allowed" }}>
          <Save size={15} /> Save
        </button>
      </div>
    </Shell>
  );
}

function FacilityModal({ facility, onClose, onSave }) {
  const [name, setName] = useState(facility.name);
  const [tagline, setTagline] = useState(facility.tagline);
  const [location, setLocation] = useState(facility.location);
  return (
    <Shell title="Edit facility" onClose={onClose}>
      <Field label="Name"><input style={inp} value={name} onChange={(e) => setName(e.target.value)} /></Field>
      <Field label="Tagline"><input style={inp} value={tagline} onChange={(e) => setTagline(e.target.value)} /></Field>
      <Field label="Location"><input style={inp} value={location} onChange={(e) => setLocation(e.target.value)} placeholder="City, State" /></Field>
      <div className="flex justify-end gap-2 mt-2">
        <button onClick={onClose} className="px-4 py-2 rounded-lg text-sm" style={{ color: BRAND.inkSoft }}>Cancel</button>
        <button onClick={() => onSave({ name: name.trim() || facility.name, tagline: tagline.trim(), location: location.trim() })} className="px-4 py-2 rounded-lg text-sm text-white" style={{ background: BRAND.ink }}>Save</button>
      </div>
    </Shell>
  );
}

function Confirm({ title, body, onClose, onYes, confirmLabel = "Delete" }) {
  return (
    <Shell title={title} onClose={onClose}>
      <p className="text-sm" style={{ color: BRAND.inkSoft }}>{body}</p>
      <div className="flex justify-end gap-2 mt-5">
        <button onClick={onClose} className="px-4 py-2 rounded-lg text-sm" style={{ color: BRAND.inkSoft }}>Cancel</button>
        <button onClick={onYes} className="px-4 py-2 rounded-lg text-sm text-white" style={{ background: "#b9472f" }}>{confirmLabel}</button>
      </div>
    </Shell>
  );
}

/* ----------------------------- Auth + API ------------------------------- */
// Where the backend API lives. Default "" = same origin as the web app.
// To point at a separate API, set window.__ECG_API_URL__ in index.html, e.g.:
//   <script>window.__ECG_API_URL__ = "https://your-api.onrender.com"</script>
const API_BASE = (typeof window !== "undefined" && window.__ECG_API_URL__) || "";

async function api(auth, path, method = "GET", body) {
  const res = await fetch(API_BASE + path, {
    method,
    headers: {
      "Content-Type": "application/json",
      ...(auth?.token ? { Authorization: `Bearer ${auth.token}` } : {}),
    },
    body: body ? JSON.stringify(body) : undefined,
  });
  if (res.status === 401) { localStorage.removeItem("ecg_token"); localStorage.removeItem("ecg_user"); }
  if (!res.ok) {
    const msg = await res.json().catch(() => ({}));
    throw new Error(msg.error || res.statusText);
  }
  return res.status === 204 ? null : res.json();
}

export default function App() {
  // If the user arrived from a reset email (?reset=TOKEN), show the reset screen.
  const resetToken = (typeof window !== "undefined")
    ? new URLSearchParams(window.location.search).get("reset")
    : null;

  const [auth, setAuth] = useState(() => {
    try {
      const token = localStorage.getItem("ecg_token");
      const user = JSON.parse(localStorage.getItem("ecg_user") || "null");
      return token && user ? { token, user } : null;
    } catch { return null; }
  });

  const login = (token, user) => {
    localStorage.setItem("ecg_token", token);
    localStorage.setItem("ecg_user", JSON.stringify(user));
    setAuth({ token, user });
  };
  const logout = () => {
    localStorage.removeItem("ecg_token");
    localStorage.removeItem("ecg_user");
    setAuth(null);
  };

  if (resetToken) return <ResetPassword token={resetToken} />;
  if (!auth) return <Login onLogin={login} />;
  return <Tracker auth={auth} onLogout={logout} />;
}

function Login({ onLogin }) {
  const [mode, setMode] = useState("signin"); // "signin" | "forgot"
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);
  const [sent, setSent] = useState(false);

  const submit = async () => {
    if (!email || !password) return;
    setBusy(true); setErr("");
    try {
      const r = await api(null, "/api/login", "POST", { email, password });
      onLogin(r.token, r.user);
    } catch (e) {
      setErr(/too many/i.test(e.message) ? e.message : "That email and password didn’t match. Try again.");
    } finally { setBusy(false); }
  };

  const sendReset = async () => {
    if (!email) return;
    setBusy(true); setErr("");
    try {
      await api(null, "/api/forgot", "POST", { email });
      setSent(true);
    } catch (e) {
      setErr(/too many/i.test(e.message) ? e.message : "Something went wrong. Please try again.");
    } finally { setBusy(false); }
  };

  const Header = (
    <div className="flex flex-col items-center text-center mb-6">
      <Crown size={40} />
      <div className="text-2xl mt-3" style={{ fontFamily: SERIF }}>Eminent Care Group</div>
      <div className="text-[11px] uppercase tracking-[0.22em] mt-1" style={{ color: BRAND.tanDeep }}>Equipment Rental Tracker</div>
    </div>
  );

  if (mode === "forgot") {
    return (
      <div className="min-h-screen flex items-center justify-center px-4" style={{ background: BRAND.paper, color: BRAND.ink }}>
        <div className="w-full max-w-sm">
          {Header}
          <div className="rounded-2xl p-6" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
            {sent ? (
              <p className="text-sm" style={{ color: BRAND.inkSoft }}>
                If an account exists for <span style={{ color: BRAND.ink }}>{email}</span>, a reset link is on its way.
                Check your inbox (and spam). The link expires in 1 hour.
              </p>
            ) : (
              <>
                <div className="text-sm mb-3" style={{ fontFamily: SERIF }}>Reset your password</div>
                <label className="block mb-4">
                  <span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Email</span>
                  <input style={inp} type="email" value={email} autoFocus
                    onChange={(e) => setEmail(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && sendReset()} />
                </label>
                {err && <div className="text-xs mb-3" style={{ color: "#9a3826" }}>{err}</div>}
                <button onClick={sendReset} disabled={busy}
                  className="w-full rounded-lg py-2.5 text-sm text-white transition-opacity"
                  style={{ background: BRAND.ink, opacity: busy ? 0.6 : 1 }}>
                  {busy ? "Sending…" : "Send reset link"}
                </button>
              </>
            )}
          </div>
          <button onClick={() => { setMode("signin"); setSent(false); setErr(""); }}
            className="block mx-auto text-xs mt-4 underline" style={{ color: BRAND.inkSoft }}>
            Back to sign in
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: BRAND.paper, color: BRAND.ink }}>
      <div className="w-full max-w-sm">
        {Header}
        <div className="rounded-2xl p-6" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
          <label className="block mb-3">
            <span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Email</span>
            <input style={inp} type="email" value={email} autoFocus
              onChange={(e) => setEmail(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && submit()} />
          </label>
          <label className="block mb-4">
            <span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Password</span>
            <input style={inp} type="password" value={password}
              onChange={(e) => setPassword(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && submit()} />
          </label>
          {err && <div className="text-xs mb-3" style={{ color: "#9a3826" }}>{err}</div>}
          <button onClick={submit} disabled={busy}
            className="w-full rounded-lg py-2.5 text-sm text-white transition-opacity"
            style={{ background: BRAND.ink, opacity: busy ? 0.6 : 1 }}>
            {busy ? "Signing in…" : "Sign in"}
          </button>
          <button onClick={() => { setMode("forgot"); setErr(""); }}
            className="block mx-auto text-xs mt-3 underline" style={{ color: BRAND.inkSoft }}>
            Forgot password?
          </button>
        </div>
        <p className="text-center text-xs mt-4" style={{ color: BRAND.inkSoft }}>
          Each facility sees only its own rentals. Corporate sees the full portfolio.
        </p>
      </div>
    </div>
  );
}

function ResetPassword({ token }) {
  const [password, setPassword] = useState("");
  const [confirm, setConfirm] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);
  const [done, setDone] = useState(false);

  const submit = async () => {
    if (password.length < 8) { setErr("Password must be at least 8 characters."); return; }
    if (password !== confirm) { setErr("The two passwords don’t match."); return; }
    setBusy(true); setErr("");
    try {
      await api(null, "/api/reset", "POST", { token, password });
      setDone(true);
    } catch (e) {
      setErr(e.message || "This reset link is invalid or has expired.");
    } finally { setBusy(false); }
  };

  const goToSignIn = () => { window.location.href = window.location.pathname; };

  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: BRAND.paper, color: BRAND.ink }}>
      <div className="w-full max-w-sm">
        <div className="flex flex-col items-center text-center mb-6">
          <Crown size={40} />
          <div className="text-2xl mt-3" style={{ fontFamily: SERIF }}>Eminent Care Group</div>
          <div className="text-[11px] uppercase tracking-[0.22em] mt-1" style={{ color: BRAND.tanDeep }}>Equipment Rental Tracker</div>
        </div>
        <div className="rounded-2xl p-6" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
          {done ? (
            <>
              <p className="text-sm mb-4" style={{ color: BRAND.inkSoft }}>Your password has been changed. You can sign in with it now.</p>
              <button onClick={goToSignIn} className="w-full rounded-lg py-2.5 text-sm text-white" style={{ background: BRAND.ink }}>Go to sign in</button>
            </>
          ) : (
            <>
              <div className="text-sm mb-3" style={{ fontFamily: SERIF }}>Choose a new password</div>
              <label className="block mb-3">
                <span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>New password</span>
                <input style={inp} type="password" value={password} autoFocus
                  onChange={(e) => setPassword(e.target.value)} />
              </label>
              <label className="block mb-4">
                <span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Confirm password</span>
                <input style={inp} type="password" value={confirm}
                  onChange={(e) => setConfirm(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && submit()} />
              </label>
              {err && <div className="text-xs mb-3" style={{ color: "#9a3826" }}>{err}</div>}
              <button onClick={submit} disabled={busy}
                className="w-full rounded-lg py-2.5 text-sm text-white transition-opacity"
                style={{ background: BRAND.ink, opacity: busy ? 0.6 : 1 }}>
                {busy ? "Saving…" : "Set new password"}
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
